#!/usr/bin/env node
/**
 * gadmin/admin/issue-plan-sync.mjs
 *
 * TODO_PLAN.md sync: regenerate an autogenerated index of open Issues
 * between sentinel markers while preserving the human-edited scratchpad
 * (everything outside the sentinels) byte-for-byte.
 *
 * Sentinels:
 *   <!-- gadmin:autogen:start -->
 *   ... generated content ...
 *   <!-- gadmin:autogen:end -->
 *
 * If the sentinels are missing, the autogen block is inserted at the top
 * of the file (after the first level-1 heading if present).
 */

import { readFileSync, writeFileSync, existsSync } from 'node:fs';

export const SENTINEL_START = '<!-- gadmin:autogen:start -->';
export const SENTINEL_END = '<!-- gadmin:autogen:end -->';

const PRIORITY_RE = /^P[0-9]$/;

/**
 * Normalize issues from either peer into a uniform shape for rendering.
 * Accepts the GH issue REST shape: { number, title, state, labels: [{name}|str] }.
 */
function normalizeIssue(it) {
  const labels = (it.labels || []).map((l) => (typeof l === 'string' ? l : l.name));
  return {
    number: it.number,
    title: it.title || '',
    state: it.state,
    labels,
    priority: labels.find((n) => PRIORITY_RE.test(n)) || 'P9',
    subsystem: (labels.find((n) => n.startsWith('subsystem:')) || 'subsystem:misc').slice('subsystem:'.length),
    blockedBy: labels.filter((n) => n.startsWith('blocked-by:')).map((n) => n.slice('blocked-by:'.length)),
    claimedBy: (labels.find((n) => n.startsWith('claimed-by:')) || '').slice('claimed-by:'.length) || null,
  };
}

/**
 * Build the autogen block content (without the sentinels).
 *
 * Format:
 *   ## Open issues (auto-generated by gadmin)
 *
 *   ### subsystem: gadmin
 *   - [ ] #123 P0 short title  (blocked-by: #42, claimed-by: claude-A)
 */
export function buildAutogenContent(issues, { generatedAt = new Date().toISOString() } = {}) {
  const norm = issues.filter((it) => it.state !== 'closed').map(normalizeIssue);
  if (norm.length === 0) {
    return [
      '## Open issues (auto-generated by gadmin)',
      '',
      `_generated ${generatedAt}. No open issues._`,
      '',
    ].join('\n');
  }
  const bySub = new Map();
  for (const it of norm) {
    if (!bySub.has(it.subsystem)) bySub.set(it.subsystem, []);
    bySub.get(it.subsystem).push(it);
  }
  for (const arr of bySub.values()) {
    arr.sort((a, b) => a.priority.localeCompare(b.priority) || a.number - b.number);
  }

  const lines = [
    '## Open issues (auto-generated by gadmin)',
    '',
    `_generated ${generatedAt}; do not hand-edit between the sentinels — run \`gadmin github issue sync-plan\` to refresh._`,
    '',
  ];
  for (const sub of [...bySub.keys()].sort()) {
    lines.push(`### subsystem: ${sub}`);
    lines.push('');
    for (const it of bySub.get(sub)) {
      const annotations = [];
      if (it.blockedBy.length) annotations.push(`blocked-by: ${it.blockedBy.join(', ')}`);
      if (it.claimedBy) annotations.push(`claimed-by: ${it.claimedBy}`);
      const suffix = annotations.length ? `  (${annotations.join('; ')})` : '';
      lines.push(`- [ ] #${it.number} ${it.priority} ${it.title}${suffix}`);
    }
    lines.push('');
  }
  return lines.join('\n');
}

/**
 * Replace (or insert) the autogen block in `original` and return the new
 * text. Scratchpad outside the sentinels is preserved byte-for-byte.
 *
 * If sentinels exist, the content between them is replaced. Otherwise the
 * block is inserted after the first H1 heading, or at the very top.
 */
export function applyAutogen(original, autogenContent) {
  const start = original.indexOf(SENTINEL_START);
  const end = original.indexOf(SENTINEL_END);
  if (start >= 0 && end > start) {
    const before = original.slice(0, start + SENTINEL_START.length);
    const after = original.slice(end);
    return `${before}\n${autogenContent}\n${after}`;
  }
  // Insert after the first level-1 heading if present, otherwise at top.
  const block = `${SENTINEL_START}\n${autogenContent}\n${SENTINEL_END}\n\n`;
  const lines = original.split('\n');
  let insertAt = 0;
  for (let i = 0; i < lines.length; i++) {
    if (/^# /.test(lines[i])) {
      insertAt = i + 1;
      // skip a single blank line after H1 if present, so the autogen block
      // sits flush below the title with one blank above
      if (lines[insertAt] === '') insertAt += 1;
      break;
    }
  }
  const head = lines.slice(0, insertAt).join('\n');
  const tail = lines.slice(insertAt).join('\n');
  const sep = head && !head.endsWith('\n\n') ? (head.endsWith('\n') ? '\n' : '\n\n') : '';
  return `${head}${sep}${block}${tail}`;
}

/**
 * Read TODO_PLAN.md, apply the autogen block, write back. Returns true if
 * the file changed.
 */
export function syncPlanFile(path, issues, opts = {}) {
  if (!existsSync(path)) {
    throw new Error(`plan file not found: ${path}`);
  }
  const original = readFileSync(path, 'utf-8');
  const autogen = buildAutogenContent(issues, opts);
  const next = applyAutogen(original, autogen);
  if (next === original) return false;
  writeFileSync(path, next, 'utf-8');
  return true;
}
